def arc_length_resample(pts, n):
    cum = [0.0]
    for i in range(1, len(pts)):
        d = _math.sqrt(sum((pts[i][k]-pts[i-1][k])**2 for k in range(3)))
        cum.append(cum[-1] + d)
    total = cum[-1]
    result = []
    for j in range(n):
        t = j * total / (n - 1)
        for k in range(len(cum)-1):
            if cum[k] <= t <= cum[k+1]:
                seg = cum[k+1] - cum[k]
                f = (t - cum[k]) / seg if seg > 0 else 0
                result.append(tuple(pts[k][d] + f*(pts[k+1][d]-pts[k][d]) for d in range(3)))
                break
    return result

def make_3d_wire(pts):
    poly = BRepBuilderAPI_MakePolygon()
    for x, y, z in pts:
        poly.Add(__import__('OCP.gp', fromlist=['gp_Pnt']).gp_Pnt(x, y, z))
    poly.Close()
    assert poly.IsDone(), "Polygon wire failed"
    return poly.Wire()

