# ── Asymmetric chamfer top & bottom ──────────────────────────────────────────
def find_horiz_face(faces, pointing_up):
    target = 1.0 if pointing_up else -1.0
    candidates = []
    for f in faces:
        try:
            nrm = f.normal_at(f.center())
        except Exception:
            continue
        if nrm.Z * target > 0.9:
            candidates.append(f)
    if not candidates:
        srt = sorted(faces, key=lambda f: f.center().Z, reverse=pointing_up)
        return srt[0]
    return sorted(candidates, key=lambda f: f.center().Z, reverse=pointing_up)[0]

top_face    = find_horiz_face(list(solid.faces()), pointing_up=True)
bottom_face = find_horiz_face(list(solid.faces()), pointing_up=False)
top_edges    = list(top_face.edges())
bottom_edges = list(bottom_face.edges())
print(f"Top face Z={top_face.center().Z:.1f} ({len(top_edges)} edges)  "
      f"Bottom face Z={bottom_face.center().Z:.1f} ({len(bottom_edges)} edges)")

chamfer_maker = BRepFilletAPI_MakeChamfer(solid.wrapped)
for e in top_edges:
    try: chamfer_maker.Add(CHAMFER_INWARD, CHAMFER_VERT, e.wrapped, top_face.wrapped)
    except: pass
for e in bottom_edges:
    try: chamfer_maker.Add(CHAMFER_INWARD, CHAMFER_VERT, e.wrapped, bottom_face.wrapped)
    except: pass
chamfer_maker.Build()
if chamfer_maker.IsDone():
    result = Solid(chamfer_maker.Shape())
    print(f"Chamfer ✓  vol={result.volume:.1f}")
else:
    print("[WARN] Chamfer failed — proceeding without chamfer")
    result = solid


