def _wire(pts):
    p = _P()
    for x,y,z in pts: p.Add(_Pt(x,y,z))
    p.Close(); return p.Wire()

def _loft(pts1, pts2):
    lb = _Thru(True, True)
    lb.AddWire(_wire(pts1)); lb.AddWire(_wire(pts2))
    lb.Build(); assert lb.IsDone(), "loft failed"
    return lb.Shape()

def _shiftz(s, dz):
    t = _Tr(); t.SetTranslation(_V(0,0,dz))
    return _T(s, t, True).Shape()

def _shifty(s, dy):
    t = _Tr(); t.SetTranslation(_V(0,dy,0))
    return _T(s, t, True).Shape()

