def _sketch_tool(pts, x_pos, y_off, z_off, dist, taper_deg):
    cy = sum(y+y_off for y,z in pts)/len(pts)
    cz = sum(z+z_off for y,z in pts)/len(pts)
    shrink = dist * _m.tan(_m.radians(taper_deg))
    avg_r  = sum(_m.sqrt((y+y_off-cy)**2+(z+z_off-cz)**2) for y,z in pts)/len(pts)
    scale  = (avg_r + shrink) / avg_r
    base = _P()
    for y,z in pts: base.Add(_Pt(x_pos, y+y_off, z+z_off))
    base.Close()
    far = _P()
    for y,z in pts:
        far.Add(_Pt(x_pos+dist, cy+((y+y_off)-cy)*scale, cz+((z+z_off)-cz)*scale))
    far.Close()
    lb = _Thru(True, True)
    lb.AddWire(base.Wire()); lb.AddWire(far.Wire())
    lb.Build(); assert lb.IsDone()
    return lb.Shape()

