# ── Boolean cuts ──────────────────────────────────────────────────
def _do_cut(base, tool, label):
    # base may be build123d Solid or raw TopoDS_Shape
    base_shape = base.wrapped if hasattr(base, 'wrapped') else base
    c = _Cut(base_shape, tool)
    c.SetFuzzyValue(0.01)
    c.Build()
    if not c.IsDone():
        print(f"[WARN] {label} cut failed")
        return base
    print(f"{label} cut ✓")
    return _BS(c.Shape())

