# ── Fuse Extrude2 and Extrude2-Copy into main body ───────────────
from OCP.BRepAlgoAPI import BRepAlgoAPI_Fuse as _FuseOp

def _do_fuse(base, tool, label):
    base_shape = base.wrapped if hasattr(base, 'wrapped') else base
    f = _FuseOp(base_shape, tool)
    f.SetFuzzyValue(0.01)
    f.Build()
    if not f.IsDone():
        print(f"[WARN] {label} fuse failed")
        return base
    print(f"{label} fuse ✓")
    return _BS(f.Shape())

