def _alrf2(pts, n):
    segs=[_mlf2.sqrt(sum((pts[i+1][k]-pts[i][k])**2 for k in range(3))) for i in range(len(pts)-1)]
    cum=[0.0]
    for s in segs: cum.append(cum[-1]+s)
    total=cum[-1]; out=[]
    for j in range(n):
        t=total*j/(n-1)
        for i in range(len(cum)-1):
            if cum[i]<=t<=cum[i+1]:
                f=(t-cum[i])/(cum[i+1]-cum[i]) if cum[i+1]>cum[i] else 0
                out.append(tuple(pts[i][k]+f*(pts[i+1][k]-pts[i][k]) for k in range(3)))
                break
    return out

